API_name: nchu_course_teachers_search_by_semester
Description:
{
  "description": "搜尋在特定學期授課的中興大學教師。",
  "required_parameters": [
    {
      "name": "semester",
      "type": "STRING",
      "description": "Semester code (e.g., \"1131\" for 113學年度第1學期)"
    }
  ],
  "optional_parameters": [
    {
      "name": "limit",
      "type": "NUMBER",
      "description": "最多回傳幾筆結果（預設為 100）",
      "default": 100
    }
  ]
}

